WHERE location_id = #{locationId}

mapper.select:
SELECT *
FROM t_location
WHERE location_name = #{locationName}
AND deleted_flag = #{deletedFlag}
AND enterprise_id = #{enterpriseId}

    AND location_id != #{excludeLocationId}

SELECT *
FROM t_location

    deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(location_name,#{queryForm.keywords}) OR
            INSTR(create_user_name,#{queryForm.keywords})
            )


        AND type = #{queryForm.type}


        AND enterprise_id = #{queryForm.enterpriseId}


        AND disabled_flag = #{queryForm.disabledFlag}



    ORDER BY create_time DESC

SELECT *
FROM t_location tc
WHERE location_id = #{locationId}
  AND deleted_flag = #{deletedFlag}

